def confusion_matrix(pred, target, normalize=False):
    num_classes = max(max(pred), max(target)) + 1
    C = torch.zeros(num_classes, num_classes)
    for p, t in zip(pred, target):
        C[p, t] += 1
    if normalize:
        C = C / C.sum(1, keepdim=True)
    return C

